code = """import json, re

# Load data
pkg_data = json.load(open(locals()['var_functions.query_db:8']))
ver_data = json.load(open(locals()['var_functions.query_db:10']))
proj_data = json.load(open(locals()['var_functions.query_db:12']))

# Find latest NPM releases
latest = {}
for p in pkg_data:
    if p.get('System') == 'NPM':
        try:
            vi = json.loads(p['VersionInfo'].strip())
            if vi.get('IsRelease'):
                name = p['Name']
                ord_val = vi['Ordinal']
                if name not in latest or ord_val > latest[name]['ord']:
                    latest[name] = {'ver': p['Version'], 'ord': ord_val}
        except:
            continue

# Get stars from projects
proj_stars = {}
for proj in proj_data:
    info = str(proj.get('Project_Information', ''))
    m = re.search(r'(\d{1,3}(?:,\d{3})*)\s+stars?', info, re.I)
    if m:
        stars = int(m.group(1).replace(',', ''))
        m2 = re.search(r'(\S+\/\S+)', info)
        if m2:
            proj_stars[m2.group(1)] = stars

# Map versions to projects  
ver_proj = {}
for v in ver_data:
    ver_proj[(v['System'], v['Name'], v['Version'])] = v['ProjectName']

# Match everything
matched = []
for name, pkg in latest.items():
    key = ('NPM', name, pkg['ver'])
    if key in ver_proj:
        proj = ver_proj[key]
        if proj in proj_stars:
            matched.append([name, pkg['ver'], proj_stars[proj]])

# Get top 5
top5 = sorted(matched, key=lambda x: x[2], reverse=True)[:5]

# Build result
result = []
for item in top5:
    result.append({"package": item[0], "version": item[1], "stars": item[2]})

print('__RESULT__:')
print(json.dumps(result))"""

